<template>
  <div class="address-list">
    <van-nav-bar
      title="我的地址"
      left-text="返回"
      left-arrow
      @click-left="$router.push('/preOrder')"
    />
    <van-address-list
      v-model="chosenAddressId"
      :list="list"
      default-tag-text="默认"
      @add="$router.push('/address/add')"
      @edit="onEdit"
      @select="select"
    />
  </div>
</template>

<script>
import $axios from '@/utils/index'
export default {
  data() {
    return {
      chosenAddressId: 0,
      list: [
        
      ],
      
    };
  },
  methods:{
      async getAddressList(){
          try {
              let res=await $axios.get('address/all')
                console.log(res)
              res.list.forEach((item,index)=>{
                 item.address=`${item.province} ${item.city} ${item.county} ${item.addressDetail}`
                 item.id=index+1
              })
              this.list=res.list
          } catch (err) {
              console.log(err)
          }
      },
      onEdit(item,index){
          this.$router.push('/address/edit/'+item.addressId)
      },
      select(item,index){
          let params=this.$route.query
          this.$router.push({
              path:'/preOrder',
              query:{
                  name:item.name,
                  tel:item.tel,
                  address:item.address.replaceAll(' ',''),
                  preOrderId:params.preOrderId
              }
          })
      }
  },
  created(){
      this.getAddressList()
  }
};
</script>

